// ╔══════════════════════════════════════════════════════╗
// ║  CONFIGURATION — Edit these values to customise     ║
// ╚══════════════════════════════════════════════════════╝
const CONFIG = {
  // Workflows not updated in this many days are considered stale
  STALE_DAYS: 90,

  // Email recipient for the summary report
  EMAIL_RECIPIENT: 'fabian@fdnxt.com',

  // Google Sheet ID for the central TAS_N8N_Audit sheet
  // Create one sheet, share with your n8n service account, paste ID here
  SHEET_ID: $env.TAS_AUDIT_SHEET_ID || 'YOUR_GOOGLE_SHEET_ID_HERE',

  // Tab name within the audit sheet
  SHEET_TAB: 'Stale_Workflows',

  // Set to true to actually deactivate stale workflows
  // Set to false for dry-run / report-only mode
  AUTO_DEACTIVATE: true,

  // Workflow name patterns to NEVER deactivate (regex strings)
  PROTECTED_PATTERNS: [
    'TAS.*Audit',
    'TAS.*Stale',
    'TAS.*Cleanup',
    'TAS.*Organiser',
    'Critical',
    'Production'
  ]
};

return [{ json: CONFIG }];

const config = $('⚙️ Configuration').first().json;
const workflows = $input.first().json.data || [];
const now = new Date();
const protectedPatterns = config.PROTECTED_PATTERNS.map(p => new RegExp(p, 'i'));

const results = [];

for (const wf of workflows) {
  const updatedAt = new Date(wf.updatedAt);
  const createdAt = new Date(wf.createdAt);
  const daysSinceUpdate = Math.floor((now - updatedAt) / (1000 * 60 * 60 * 24));
  const daysSinceCreated = Math.floor((now - createdAt) / (1000 * 60 * 60 * 24));
  const isStale = daysSinceUpdate > config.STALE_DAYS;
  const isProtected = protectedPatterns.some(p => p.test(wf.name));
  const tagNames = (wf.tags || []).map(t => t.name).join(', ');

  let action = 'NONE';
  let reason = '';

  if (isStale && wf.active && !isProtected && config.AUTO_DEACTIVATE) {
    action = 'DEACTIVATE';
    reason = `Active but untouched for ${daysSinceUpdate} days`;
  } else if (isStale && wf.active && isProtected) {
    action = 'PROTECTED_SKIP';
    reason = `Stale but matches protected pattern — skipped`;
  } else if (isStale && !wf.active) {
    action = 'FLAG_INACTIVE';
    reason = `Already inactive, untouched ${daysSinceUpdate} days — candidate for deletion`;
  } else {
    action = 'OK';
    reason = 'Within retention window';
  }

  results.push({
    workflowId: wf.id,
    workflowName: wf.name,
    active: wf.active,
    tags: tagNames,
    createdAt: wf.createdAt,
    updatedAt: wf.updatedAt,
    daysSinceUpdate,
    daysSinceCreated,
    isStale,
    isProtected,
    action,
    reason,
    timestamp: now.toISOString()
  });
}

// Sort: actionable items first
results.sort((a, b) => {
  const order = { DEACTIVATE: 0, PROTECTED_SKIP: 1, FLAG_INACTIVE: 2, OK: 3 };
  return (order[a.action] || 99) - (order[b.action] || 99);
});

return results.map(r => ({ json: r }));

const allItems = $('Analyse Staleness').all();
const config = $('⚙️ Configuration').first().json;

const deactivated = allItems.filter(i => i.json.action === 'DEACTIVATE');
const protectedSkipped = allItems.filter(i => i.json.action === 'PROTECTED_SKIP');
const flaggedInactive = allItems.filter(i => i.json.action === 'FLAG_INACTIVE');
const ok = allItems.filter(i => i.json.action === 'OK');

const tableRows = allItems
  .filter(i => i.json.isStale)
  .map(i => {
    const w = i.json;
    const badge = w.action === 'DEACTIVATE' ? '🔴 DEACTIVATED'
      : w.action === 'PROTECTED_SKIP' ? '🛡️ PROTECTED'
      : w.action === 'FLAG_INACTIVE' ? '⚠️ INACTIVE/STALE'
      : '✅ OK';
    return `<tr><td>${w.workflowName}</td><td>${w.workflowId}</td><td>${w.daysSinceUpdate}d</td><td>${w.tags || 'none'}</td><td>${badge}</td><td>${w.reason}</td></tr>`;
  }).join('');

const html = `
<h2>🔍 TAS Stale Workflow Report</h2>
<p><strong>Run:</strong> ${new Date().toISOString()}</p>
<p><strong>Threshold:</strong> ${config.STALE_DAYS} days</p>
<hr>
<table style="border-collapse:collapse;width:100%">
<tr><th>Metric</th><th>Count</th></tr>
<tr><td>Total workflows scanned</td><td><strong>${allItems.length}</strong></td></tr>
<tr><td>🔴 Deactivated this run</td><td><strong>${deactivated.length}</strong></td></tr>
<tr><td>🛡️ Protected (skipped)</td><td><strong>${protectedSkipped.length}</strong></td></tr>
<tr><td>⚠️ Flagged inactive/stale</td><td><strong>${flaggedInactive.length}</strong></td></tr>
<tr><td>✅ Healthy</td><td><strong>${ok.length}</strong></td></tr>
</table>
<hr>
<h3>Stale Workflow Details</h3>
<table style="border-collapse:collapse;width:100%" border="1" cellpadding="6">
<tr><th>Name</th><th>ID</th><th>Age</th><th>Tags</th><th>Action</th><th>Reason</th></tr>
${tableRows || '<tr><td colspan="6">No stale workflows found 🎉</td></tr>'}
</table>
<hr>
<p><em>Full audit trail logged to Google Sheet: TAS_N8N_Audit → Stale_Workflows</em></p>
`;

return [{ json: { html, recipient: config.EMAIL_RECIPIENT, subject: `TAS N8N Audit: ${deactivated.length} deactivated, ${flaggedInactive.length} flagged — ${allItems.length} scanned` } }];
